    status TEXT NOT NULL DEFAULT 'active',
    created_at REAL NOT NULL,
    updated_at REAL NOT NULL,
    merged_into TEXT,
    enable_stacked_review INTEGER NOT NULL DEFAULT 0,
    metadata TEXT DEFAULT '{}'
