  CREATE TABLE IF NOT EXISTS operations (...);
  CREATE TABLE IF NOT EXISTS worktrees (...);
  CREATE TABLE IF NOT EXISTS stream_locks (...);
  CREATE TABLE IF NOT EXISTS stream_guards (...);
